import { execFileSync } from "node:child_process";
import { readFileSync, writeFileSync } from "node:fs";

function tigrisJSON(args) {
  try {
    const stdout = execFileSync("tigris", args, { encoding: "utf8" });
    return JSON.parse(stdout);
  } catch (error) {
    console.error(`Error executing tigris ${args.join(" ")}:`, error.message);
    throw error;
  }
}

const trialId = readFileSync("/logs/artifacts/trial_id", "utf8").trim();
const PREFIX = `harbor-inv-${trialId}-`.toLowerCase().replace(/[^a-z0-9.-]/g, "-");

const bucketsPayload = tigrisJSON(["buckets", "list", "--format", "json"]);

// Handle different possible response formats for buckets list
let allBuckets = [];
if (Array.isArray(bucketsPayload)) {
  allBuckets = bucketsPayload;
} else if (bucketsPayload.items) {
  allBuckets = bucketsPayload.items;
} else if (bucketsPayload.buckets) {
  allBuckets = bucketsPayload.buckets;
}

const targetNames = allBuckets
  .map((b) => b.name)
  .filter((name) => typeof name === "string" && name.startsWith(PREFIX))
  .sort();

const inventory = {};
let total = 0;

for (const name of targetNames) {
  const snapsPayload = tigrisJSON(["snapshots", "list", name, "--format", "json"]);

  // Handle different possible response formats for snapshots list
  let snaps = [];
  if (Array.isArray(snapsPayload)) {
    snaps = snapsPayload;
  } else if (snapsPayload.snapshots) {
    snaps = snapsPayload.snapshots;
  } else if (snapsPayload.items) {
    snaps = snapsPayload.items;
  }

  const versions = snaps
    .map((s) => s.version)
    .filter(Boolean)
    .sort();

  inventory[name] = versions;
  total += versions.length;
}

writeFileSync("/home/user/inv/inventory.json", JSON.stringify(inventory, null, 2) + "\n");
console.log(`${targetNames.length} buckets, ${total} snapshots`);

